     5→//! Parade command - Display comprehensive Heat status for project review
     6→//!
     7→//! Implements both heat view (Firemark) and pace view (Coronet).
     8→
     9→use crate::jjrf_favor::jjrf_Firemark as Firemark;
    10→use crate::jjrf_favor::jjrf_Coronet as Coronet;
    11→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_HeatStatus as HeatStatus, jjrg_PaceState as PaceState};
    12→use crate::jjrp_print::{jjrp_Table, jjrp_Column, jjrp_Align};
    13→use std::fs;
    14→
    15→/// Arguments for jjx_parade command
    16→#[derive(clap::Args, Debug)]
    17→pub struct jjrpd_ParadeArgs {
    18→    /// Path to the Gallops JSON file
    19→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
    20→    pub file: std::path::PathBuf,
    21→
    22→    /// Target: Firemark (heat view) or Coronet (pace view). If omitted, uses first racing heat.
    23→    pub target: Option<String>,
    24→
    25→    /// Show paddock and full specs (heat mode only)
    26→    #[arg(long)]
    27→    pub full: bool,
    28→
    29→    /// Show only remaining paces (exclude complete/abandoned)
    30→    #[arg(long)]
    31→    pub remaining: bool,
    32→}
    33→
    34→/// Run the parade command - display comprehensive Heat status
    35→pub fn jjrpd_run_parade(args: jjrpd_ParadeArgs) -> i32 {
    36→    let gallops = match Gallops::jjrg_load(&args.file) {
    37→        Ok(g) => g,
    38→        Err(e) => {
    39→            eprintln!("jjx_parade: error: {}", e);
    40→            return 1;
    41→        }
    42→    };
    43→
    44→    // Resolve target: use provided value or auto-select first racing heat
    45→    let target = match args.target {
    46→        Some(t) => t,
    47→        None => {
    48→            // Load gallops to resolve default heat
    49→            match zjjrpd_resolve_default_heat(&gallops) {
    50→                Ok(fm) => fm,
    51→                Err(e) => {
    52→                    eprintln!("jjx_parade: error: {}", e);
    53→                    return 1;
    54→                }
    55→            }
    56→        }
    57→    };
    58→
    59→    // Determine target type by length
    60→    let target_str = target.strip_prefix('₢').or_else(|| target.strip_prefix('₣')).unwrap_or(&target);
    61→
    62→    if target_str.len() == 5 {
    63→        // Coronet - pace view
    64→        let coronet = match Coronet::jjrf_parse(&target) {
    65→            Ok(c) => c,
    66→            Err(e) => {
    67→                eprintln!("jjx_parade: error: {}", e);
    68→                return 1;
    69→            }
    70→        };
    71→
    72→        // Extract parent firemark
    73→        let firemark = coronet.jjrf_parent_firemark();
    74→        let heat_key = firemark.jjrf_display();
    75→        let heat = match gallops.heats.get(&heat_key) {
    76→            Some(h) => h,
    77→            None => {
    78→                eprintln!("jjx_parade: error: Heat '{}' not found", heat_key);
    79→                return 1;
    80→            }
    81→        };
    82→
    83→        // Find pace
    84→        let coronet_key = coronet.jjrf_display();
    85→        let pace = match heat.paces.get(&coronet_key) {
    86→            Some(p) => p,
    87→            None => {
    88→                eprintln!("jjx_parade: error: Pace '{}' not found in Heat '{}'", coronet_key, heat_key);
    89→                return 1;
    90→            }
    91→        };
    92→
    93→        // Display tack history - iterate in reverse order (oldest first)
    94→        if !pace.tacks.is_empty() {
    95→            // Print header with current state from tacks[0]
    96→            let current_tack = &pace.tacks[0];
    97→            println!("Pace: {} ({})", current_tack.silks, coronet_key);
    98→            println!("Heat: {}", heat_key);
    99→            println!();
   100→
   101→            // Iterate tacks in reverse order (oldest first)
   102→            for (index, tack) in pace.tacks.iter().rev().enumerate() {
   103→                let state_str = zjjrpd_pace_state_str(&tack.state);
   104→                let basis_str = if tack.basis == "0000000" {
   105→                    "(no basis)".to_string()
   106→                } else {
   107→                    tack.basis.clone()
   108→                };
   109→
   110→                println!("[{}] {} (basis: {})", index, state_str, basis_str);
   111→                println!("    Silks: {}", tack.silks);
   112→                if let Some(ref direction) = tack.direction {
   113→                    println!("    Direction: {}", direction);
   114→                }
   115→                println!();
   116→                // Indent spec text
   117→                for line in tack.text.lines() {
   118→                    println!("    {}", line);
   119→                }
   120→                println!();
   121→            }
   122→        }
   123→    } else if target_str.len() == 2 {
   124→        // Firemark - heat view
   125→        let firemark = match Firemark::jjrf_parse(&target) {
   126→            Ok(fm) => fm,
   127→            Err(e) => {
   128→                eprintln!("jjx_parade: error: {}", e);
   129→                return 1;
   130→            }
   131→        };
   132→
   133→        let heat_key = firemark.jjrf_display();
   134→        let heat = match gallops.heats.get(&heat_key) {
   135→            Some(h) => h,
   136→            None => {
   137→                eprintln!("jjx_parade: error: Heat '{}' not found", heat_key);
   138→                return 1;
   139→            }
   140→        };
   141→
   142→        if args.full {
   143→            // Full view: paddock + all specs
   144→            let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   145→                Ok(content) => content,
   146→                Err(e) => {
   147→                    eprintln!("jjx_parade: error reading paddock file '{}': {}", heat.paddock_file, e);
   148→                    return 1;
   149→                }
   150→            };
   151→
   152→            let status_str = match heat.status {
   153→                HeatStatus::Racing => "racing",
   154→                HeatStatus::Stabled => "stabled",
   155→                HeatStatus::Retired => "retired",
   156→            };
   157→
   158→            println!("Heat: {} ({})", heat.silks, heat_key);
   159→            println!("Status: {}", status_str);
   160→            println!("Created: {}", heat.creation_time);
   161→            println!();
   162→            println!("## Paddock");
   163→            println!();
   164→            println!("{}", paddock_content);
   165→            println!();
   166→            println!("## Paces");
   167→            println!();
   168→
   169→            for coronet_key in &heat.order {
   170→                if let Some(pace) = heat.paces.get(coronet_key) {
   171→                    if let Some(tack) = pace.tacks.first() {
   172→                        // Skip complete/abandoned if --remaining
   173→                        if args.remaining && (tack.state == PaceState::Complete || tack.state == PaceState::Abandoned) {
   174→                            continue;
   175→                        }
   176→                        let state_str = zjjrpd_pace_state_str(&tack.state);
   177→                        println!("### {} ({}) [{}]", tack.silks, coronet_key, state_str);
   178→                        println!();
   179→                        println!("{}", tack.text);
   180→                        if let Some(ref direction) = tack.direction {
   181→                            println!();
   182→                            println!("**Direction:** {}", direction);
   183→                        }
   184→                        println!();
   185→                    }
   186→                }
   187→            }
   188→        } else {
   189→            // List view: numbered paces
   190→            // If --remaining, output markdown format
   191→            if args.remaining {
   192→                let mut complete_count = 0;
   193→                let mut abandoned_count = 0;
   194→                let mut rough_count = 0;
   195→                let mut bridled_count = 0;
   196→                let mut remaining_paces: Vec<(&String, &crate::jjrg_gallops::jjrg_Pace)> = Vec::new();
   197→                let mut first_remaining_pace: Option<(&String, &crate::jjrg_gallops::jjrg_Pace)> = None;
   198→
   199→                for coronet_key in &heat.order {
   200→                    if let Some(pace) = heat.paces.get(coronet_key) {
   201→                        if let Some(tack) = pace.tacks.first() {
   202→                            match tack.state {
   203→                                PaceState::Complete => complete_count += 1,
   204→                                PaceState::Abandoned => abandoned_count += 1,
   205→                                PaceState::Rough => {
   206→                                    rough_count += 1;
   207→                                    remaining_paces.push((coronet_key, pace));
   208→                                    if first_remaining_pace.is_none() {
   209→                                        first_remaining_pace = Some((coronet_key, pace));
   210→                                    }
   211→                                }
   212→                                PaceState::Bridled => {
   213→                                    bridled_count += 1;
   214→                                    remaining_paces.push((coronet_key, pace));
   215→                                    if first_remaining_pace.is_none() {
   216→                                        first_remaining_pace = Some((coronet_key, pace));
   217→                                    }
   218→                                }
   219→                            }
   220→                        }
   221→                    }
   222→                }
   223→
   224→                let status_str = match heat.status {
   225→                    HeatStatus::Racing => "racing",
   226→                    HeatStatus::Stabled => "stabled",
   227→                    HeatStatus::Retired => "retired",
   228→                };
   229→
   230→                let remaining_count = rough_count + bridled_count;
   231→
   232→                // Header line with heat info
   233→                println!("Heat: {} ({}) [{}]", heat.silks, heat_key, status_str);
   234→                println!("Progress: {} complete | {} abandoned | {} remaining ({} rough, {} bridled)",
   235→                    complete_count, abandoned_count, remaining_count, rough_count, bridled_count);
   236→                println!();
   237→
   238→                // Table with remaining paces
   239→                if !remaining_paces.is_empty() {
   240→                    // Set up table with column definitions
   241→                    let mut table = jjrp_Table::jjrp_new(vec![
   242→                        jjrp_Column::new("No", jjrp_Align::Right),
   243→                        jjrp_Column::new("State", jjrp_Align::Left),
   244→                        jjrp_Column::new("Pace", jjrp_Align::Left),
   245→                        jjrp_Column::new("₢Coronet", jjrp_Align::Left),
   246→                    ]);
   247→
   248→                    // Measure all rows to compute column widths
   249→                    for (idx, (coronet_key, pace)) in remaining_paces.iter().enumerate() {
   250→                        if let Some(tack) = pace.tacks.first() {
   251→                            let state_str = zjjrpd_pace_state_str(&tack.state);
   252→                            table.jjrp_measure(&[
   253→                                &(idx + 1).to_string(),
   254→                                state_str,
   255→                                &tack.silks,
   256→                                coronet_key,
   257→                            ]);
   258→                        }
   259→                    }
   260→
   261→                    // Print header and separator
   262→                    table.jjrp_print_header();
   263→                    table.jjrp_print_separator();
   264→
   265→                    // Print data rows
   266→                    for (idx, (coronet_key, pace)) in remaining_paces.iter().enumerate() {
   267→                        if let Some(tack) = pace.tacks.first() {
   268→                            let state_str = zjjrpd_pace_state_str(&tack.state);
   269→                            table.jjrp_print_row(&[
   270→                                &(idx + 1).to_string(),
   271→                                state_str,
   272→                                &tack.silks,
   273→                                coronet_key,
   274→                            ]);
   275→                        }
   276→                    }
   277→                    println!();
   278→                }
   279→
   280→                // Next up callout
   281→                if let Some((coronet_key, pace)) = first_remaining_pace {
   282→                    if let Some(tack) = pace.tacks.first() {
   283→                        let state_str = zjjrpd_pace_state_str(&tack.state);
   284→                        println!("Next: {} ({}) [{}]", tack.silks, coronet_key, state_str);
   285→                    }
   286→                }
   287→            } else {
   288→                // Column-justified list view (all paces)
   289→                // Set up table with column definitions
   290→                let mut table = jjrp_Table::jjrp_new(vec![
   291→                    jjrp_Column::new("No", jjrp_Align::Right),
   292→                    jjrp_Column::new("State", jjrp_Align::Left),
   293→                    jjrp_Column::new("Pace", jjrp_Align::Left),
   294→                    jjrp_Column::new("₢Coronet", jjrp_Align::Left),
   295→                ]);
   296→
   297→                // Measure all rows to compute column widths
   298→                let mut num = 0;
   299→                for coronet_key in &heat.order {
   300→                    if let Some(pace) = heat.paces.get(coronet_key) {
   301→                        if let Some(tack) = pace.tacks.first() {
   302→                            num += 1;
   303→                            let state_str = zjjrpd_pace_state_str(&tack.state);
   304→                            table.jjrp_measure(&[
   305→                                &num.to_string(),
   306→                                state_str,
   307→                                &tack.silks,
   308→                                coronet_key,
   309→                            ]);
   310→                        }
   311→                    }
   312→                }
   313→
   314→                // Print header and separator
   315→                table.jjrp_print_header();
   316→                table.jjrp_print_separator();
   317→
   318→                // Print data rows
   319→                let mut num = 0;
   320→                for coronet_key in &heat.order {
   321→                    if let Some(pace) = heat.paces.get(coronet_key) {
   322→                        if let Some(tack) = pace.tacks.first() {
   323→                            num += 1;
   324→                            let state_str = zjjrpd_pace_state_str(&tack.state);
   325→                            table.jjrp_print_row(&[
   326→                                &num.to_string(),
   327→                                state_str,
   328→                                &tack.silks,
   329→                                coronet_key,
   330→                            ]);
   331→                        }
   332→                    }
   333→                }
   334→            }
   335→        }
   336→    } else {
   337→        eprintln!("jjx_parade: error: target must be Firemark (2 chars) or Coronet (5 chars), got {} chars", target_str.len());
   338→        return 1;
   339→    }
   340→
   341→    0
   342→}
   343→
   344→/// Helper to convert PaceState to display string
   345→pub(crate) fn zjjrpd_pace_state_str(state: &PaceState) -> &'static str {
   346→    match state {
   347→        PaceState::Rough => "rough",
   348→        PaceState::Bridled => "bridled",
   349→        PaceState::Complete => "complete",
   350→        PaceState::Abandoned => "abandoned",
   351→    }
   352→}
   353→
   354→/// Resolve the default heat (first racing heat) when no target is specified
   355→pub(crate) fn zjjrpd_resolve_default_heat(gallops: &Gallops) -> Result<String, String> {
   356→    for (heat_key, heat) in &gallops.heats {
   357→        if heat.status == HeatStatus::Racing {
   358→            return Ok(heat_key.clone());
   359→        }
   360→    }
   361→    Err("No racing heats found".to_string())
   362→}
