     4→//! Tests for jjx_parade command (heat/pace display)
     5→
     6→use super::jjrpd_parade::{zjjrpd_pace_state_str, zjjrpd_resolve_default_heat};
     7→use super::jjrg_gallops::{jjrg_Gallops, jjrg_Heat, jjrg_Pace, jjrg_Tack, jjrg_HeatStatus, jjrg_PaceState, JJRG_UNKNOWN_BASIS};
     8→use std::collections::BTreeMap;
     9→use indexmap::IndexMap;
    10→
    11→// ===== Helper functions =====
    12→
    13→fn make_valid_gallops() -> jjrg_Gallops {
    14→    jjrg_Gallops {
    15→        next_heat_seed: "AB".to_string(),
    16→        heats: IndexMap::new(),
    17→    }
    18→}
    19→
    20→fn make_valid_tack(state: jjrg_PaceState, silks: &str) -> jjrg_Tack {
    21→    jjrg_Tack {
    22→        ts: "260101-1200".to_string(),
    23→        state,
    24→        text: "Test tack text".to_string(),
    25→        silks: silks.to_string(),
    26→        basis: JJRG_UNKNOWN_BASIS.to_string(),
    27→        direction: None,
    28→    }
    29→}
    30→
    31→fn make_valid_pace(heat_id: &str) -> (String, jjrg_Pace) {
    32→    let pace_key = format!("₢{}AAA", heat_id);
    33→    let pace = jjrg_Pace {
    34→        tacks: vec![make_valid_tack(jjrg_PaceState::Rough, "test-pace")],
    35→    };
    36→    (pace_key, pace)
    37→}
    38→
    39→fn make_valid_heat(heat_id: &str, silks: &str, status: jjrg_HeatStatus) -> (String, jjrg_Heat) {
    40→    let heat_key = format!("₣{}", heat_id);
    41→    let (pace_key, pace) = make_valid_pace(heat_id);
    42→    let mut paces = BTreeMap::new();
    43→    paces.insert(pace_key.clone(), pace);
    44→
    45→    let heat = jjrg_Heat {
    46→        silks: silks.to_string(),
    47→        creation_time: "260101".to_string(),
    48→        status,
    49→        order: vec![pace_key],
    50→        next_pace_seed: "AAB".to_string(),
    51→        paddock_file: format!(".claude/jjm/jjp_{}.md", heat_id),
    52→        paces,
    53→    };
    54→    (heat_key, heat)
