    21→/// Resolve the default heat (first racing heat) when no target is specified
    22→pub fn jjrq_resolve_default_heat(gallops: &Gallops) -> Result<String, String> {
    23→    for (heat_key, heat) in &gallops.heats {
    24→        if heat.status == HeatStatus::Racing {
    25→            return Ok(heat_key.clone());
    26→        }
    27→    }
    28→    Err("No racing heats found".to_string())
    29→}
