    65→// ============================================================================
    66→// Silks Sequence Parsing and Building
    67→// ============================================================================
    68→
    69→/// Parse silks into (base, sequence_number)
    70→///
    71→/// Silks ending with a 2-digit sequence number are parsed into base and number.
    72→/// Format: "foo-bar" -> ("foo-bar", None)
    73→///         "foo-bar-01" -> ("foo-bar", Some(1))
    74→///         "foo-bar-42" -> ("foo-bar", Some(42))
    75→pub fn jjrq_parse_silks_sequence(silks: &str) -> (String, Option<u32>) {
    76→    // Use regex ^(.+)-(\d{2})$ for suffix detection
    77→    let re = match Regex::new(r"^(.+)-(\d{2})$") {
    78→        Ok(r) => r,
    79→        Err(_) => {
    80→            // Fallback: return full silks as base, no sequence
    81→            return (silks.to_string(), None);
    82→        }
    83→    };
    84→
    85→    if let Some(caps) = re.captures(silks) {
    86→        if let (Some(base_match), Some(num_match)) = (caps.get(1), caps.get(2)) {
    87→            let base = base_match.as_str().to_string();
    88→            if let Ok(num_str) = num_match.as_str().parse::<u32>() {
    89→                return (base, Some(num_str));
    90→            }
    91→        }
    92→    }
    93→
    94→    // No match: return full silks as base, no sequence
    95→    (silks.to_string(), None)
    96→}
    97→
    98→/// Build garlanded silks: "garlanded-{base}-{seq:02}"
    99→pub fn jjrq_build_garlanded_silks(base: &str, seq: u32) -> String {
   100→    format!("garlanded-{}-{:02}", base, seq)
   101→}
   102→
   103→/// Build continuation silks: "{base}-{seq:02}"
   104→pub fn jjrq_build_continuation_silks(base: &str, seq: u32) -> String {
   105→    format!("{}-{:02}", base, seq)
   106→}
